( '2aebf8dc-227c-4c25-99a9-d357e375f42c', null, '销售方法：B2B 终极指南', '本指南将介绍一些最有效的 B2B 销售方法，帮助您了解如何根据自身情况选择正确的方法，并说明正确的客户关系管理软件对于成功实施和取得一致结果的关键作用。', '["SaaS","general","客户","销售"]', 'SaaS', 0.7, 'ACTIVE', 'general', null, null, null, null, NOW() ),
( '8fef13a0-f3e5-400a-9e69-80d26a1431c3', null, '销售方法：B2B 终极指南', '除了内部效益之外，掌握一种方法也是一种竞争优势。当产品看起来相似时，销售体验本身往往是决定性因素。研究表明，一半以上的客户忠诚度是由这种体验驱动的。', '["SaaS","general","客户","销售"]', 'SaaS', 0.7, 'ACTIVE', 'general', null, null, null, null, NOW() ),
