( '95bdc9fb-55ab-4d17-ac6c-c8a16eecb1a5', null, '做销售怎么经营朋友圈?', '换句话说，如果你想用朋友圈获得财富，可以把它当成自媒体，当成一门生意而不是自家的客厅随便造。这门生意需要我们想好自己的产品是什么（内容），还要去找客户（微信好友精准流量），客户维系（私人关系维护/活动裂变）。', '["通用","social_selling","客户","朋友圈"]', '通用', 0.7, 'ACTIVE', 'social_selling', null, null, null, null, NOW() ),
( '291a37b4-195b-4a4c-9683-f194443db2e1', null, '做销售怎么经营朋友圈?', '如果一个人只想通过朋友圈来赚钱，那么过硬的专业本领+引流能力+表达能力缺一不可。但如果一个人想展示有价值的内容或美好的东西，来获得别人的认可，「真诚」+「爱分享」+「积累」就可以了。', '["通用","social_selling","朋友圈","价值"]', '通用', 0.7, 'ACTIVE', 'social_selling', null, null, null, null, NOW() ),
( '147b70c3-32ca-437a-9622-323d0c19cc59', null, '做销售怎么经营朋友圈?', '这样的朋友圈，不像上一篇文章举例那样富有销售机会，但是这样的朋友圈，评论的得当却可以拉近你们的距离，让对方视你为知己。', '["通用","social_selling","销售","朋友圈"]', '通用', 0.7, 'ACTIVE', 'social_selling', null, null, null, null, NOW() ),
( '6749fa78-2c5a-4c7d-847f-abe0af6f7029', null, '做销售怎么经营朋友圈?', '对于这种没有销售机会的朋友圈，我们也会提炼出一个评论公式，没有销售机会的朋友圈评论公式：赞美+原因+细节+请求', '["通用","social_selling","销售","朋友圈"]', '通用', 0.7, 'ACTIVE', 'social_selling', null, null, null, null, NOW() ),
